apt-get update && apt-get install -y python3 python3-pip gcc file zip unzip tar gzip
pip3 install pytest

mkdir -p /home/user/raw_source
cd /home/user/raw_source

# Create older ELF (Should be processed)
cat << 'EOF' > dummy.c
int main() { return 0; }
EOF
gcc dummy.c -o a1b2c3d4
rm dummy.c
touch -d "2023-05-15" a1b2c3d4

# Create newer ELF (Should be ignored)
cat << 'EOF' > dummy2.c
int main() { return 1; }
EOF
gcc dummy2.c -o e5f6g7h8
rm dummy2.c
touch -d "2024-02-10" e5f6g7h8

# Create GCode (Should be processed)
cat << 'EOF' > x9y8z7w6
; BEGIN GCODE
; Generated by Slicer
; ModelName: Extruder_Gear
G28 ; home all axes
G1 Z5 F5000 ; lift nozzle
EOF
touch -d "2022-11-20" x9y8z7w6

# Create GCode (Should be ignored)
cat << 'EOF' > m1n2o3p4
; BEGIN GCODE
; ModelName: Invalid_Model
G28
EOF
touch -d "2024-05-01" m1n2o3p4

# Create SQLite WAL (Should be processed)
# Using magic bytes directly to avoid sqlite3 journal auto-deletion issues
printf '\x37\x7f\x06\x82\x00\x00\x00\x00' > j5k4l3m2
touch -d "2023-12-30" j5k4l3m2

# Package
cd /home/user
tar -czf raw_assets.tar.gz -C raw_source .
rm -rf raw_source

useradd -m -s /bin/bash user || true
chmod -R 777 /home/user